mapper.select:
SELECT user_id, total_xp, level, master_xp
FROM user_progress
WHERE user_id = #{userId}

SELECT COALESCE(xp_sum, 0)
FROM daily_xp
WHERE user_id = #{userId} AND day = #{day}

SELECT COUNT(*)
FROM xp_log
WHERE user_id = #{userId}
  AND action_type = #{actionType}
  AND earned_date = #{day}

SELECT user_id, current_streak, last_action_date
FROM user_streak
WHERE user_id = #{userId}
